import{_ as o,o as t,c as n,a2 as a}from"./chunks/framework.BYlK8ftn.js";const h=JSON.parse('{"title":"Dev tools","description":"","frontmatter":{},"headers":[],"relativePath":"guide/dev-tools.md","filePath":"guide/dev-tools.md","lastUpdated":1782051934000}'),r={name:"guide/dev-tools.md"};function d(s,e,l,c,i,u){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="dev-tools" tabindex="-1">Dev tools <a class="header-anchor" href="#dev-tools" aria-label="Permalink to &quot;Dev tools&quot;">​</a></h1><p>Developer-only conveniences that are gated out of production builds. They exist to help inspect and debug the game; none of them change shipped behaviour.</p><h2 id="unlock-all-zones-flo-469" tabindex="-1">Unlock all zones (FLO-469) <a class="header-anchor" href="#unlock-all-zones-flo-469" aria-label="Permalink to &quot;Unlock all zones (FLO-469)&quot;">​</a></h2><p>By default the world map gates fast-travel behind sequential conquest: a world opens only once the previous one is conquered (ADR 0005, see <a href="./world-map">World map &amp; zones</a>). To <strong>inspect every map</strong> without playing through the campaign, a dev-only override marks all registered zones (<code>forest</code>, <code>human-lands</code>, <code>empire</code>, <code>mountains</code>) as unlocked, so each is selectable and travelable from the world-map overlay (press <strong>M</strong> in play).</p><p>It is <strong>travel/routing only</strong> — it does not grant conquest credit, write to the save, or alter any other progression. Production builds are unaffected.</p><h3 id="turning-it-on" tabindex="-1">Turning it on <a class="header-anchor" href="#turning-it-on" aria-label="Permalink to &quot;Turning it on&quot;">​</a></h3><p>The gate is resolved by <code>isDevZoneUnlockEnabled()</code> in <a href="../../src/game/world/devUnlock.ts"><code>src/game/world/devUnlock.ts</code></a>, read once at startup in <code>App</code>. Resolution (first match wins):</p><table tabindex="0"><thead><tr><th>Condition</th><th>Unlock all zones?</th></tr></thead><tbody><tr><td><code>VITE_DEV_UNLOCK_ZONES=true</code></td><td><strong>on</strong> — even in a built/preview bundle</td></tr><tr><td><code>VITE_DEV_UNLOCK_ZONES=false</code></td><td><strong>off</strong> — even in a dev build (exercise the real gate)</td></tr><tr><td>flag unset, <code>npm run dev</code></td><td><strong>on</strong> (dev build default)</td></tr><tr><td>flag unset, prod build</td><td><strong>off</strong></td></tr></tbody></table><p>So the common cases need no setup:</p><ul><li><strong>Local inspection:</strong> <code>npm run dev</code> → open the app, press <strong>M</strong>, travel anywhere.</li><li><strong>Test the real conquest gate in dev:</strong> <code>VITE_DEV_UNLOCK_ZONES=false npm run dev</code>.</li><li><strong>Deployed preview the board can poke:</strong> build with <code>VITE_DEV_UNLOCK_ZONES=true npm run build</code> (do <strong>not</strong> set this on the production deploy).</li></ul><blockquote><p>⚠️ Do not set <code>VITE_DEV_UNLOCK_ZONES=true</code> for the production Cloudflare Pages build — that would ship the override and let real players skip progression.</p></blockquote><h3 id="scene-caveat" tabindex="-1">Scene caveat <a class="header-anchor" href="#scene-caveat" aria-label="Permalink to &quot;Scene caveat&quot;">​</a></h3><p>Every zone has its own scene (<code>createZoneScene</code> in <a href="../../src/scenes/zoneScenes.ts"><code>src/scenes/zoneScenes.ts</code></a>): <code>forest</code>, <code>human-lands</code>, <code>empire</code> (palace) and <code>mountains</code> (Black Crown Pass). Travelling with the override mounts each zone&#39;s real scene — there is no forest fallback for the unlocked maps.</p>',13)])])}const g=o(r,[["render",d]]);export{h as __pageData,g as default};
